import React, { useEffect, useState } from "react";
import "./App.css";

function App() {
  const API_URL = "http://localhost:5000/api/reports";

  const [view, setView] = useState("home"); // "home" | "form"
  const [loading, setLoading] = useState(false);
  const [reports, setReports] = useState([]);

  // Campos del formulario
  const [type, setType] = useState("Basura acumulada");
  const [description, setDescription] = useState("");
  const [location, setLocation] = useState("");
  const [contact, setContact] = useState("");
  const [priority, setPriority] = useState("media");
  const [zone, setZone] = useState("");
  // Mapa: construir URL de Google Maps según ubicación / zona
  const buildMapUrl = (loc, zn) => {
    const base = "Barrio Balboa, La Chorrera, Panamá";
    const query = (loc || zn || base).trim();
    return `https://www.google.com/maps?q=${encodeURIComponent(
      query
    )}&output=embed`;
  };

  const [mapPreviewUrl, setMapPreviewUrl] = useState(buildMapUrl());

  useEffect(() => {
    setMapPreviewUrl(buildMapUrl(location, zone));
  }, [location, zone]);

  // -------------------------
  // Cargar reportes del backend
  // -------------------------
  const fetchReports = async () => {
    try {
      setLoading(true);
      const res = await fetch(API_URL);
      const data = await res.json();
      setReports(data);
    } catch (error) {
      alert("No se pudieron cargar los reportes desde el servidor.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchReports();
  }, []);

  // -------------------------
  // Enviar nuevo reporte
  // -------------------------
  const submitReport = async (e) => {
    e.preventDefault();

    try {
      const res = await fetch(API_URL, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          type,
          description,
          location,
          contact,
          priority,
          zone,
        }),
      });

      if (!res.ok) throw new Error("Error en el servidor");

      alert("Reporte registrado en el servidor.");
      // Limpiar campos
      setDescription("");
      setLocation("");
      setContact("");
      setPriority("media");
      setZone("");

      // Volver al inicio y recargar lista
      await fetchReports();
      setView("home");
    } catch (error) {
      alert("Hubo un problema al registrar el reporte.");
    }
  };

  // -------------------------
  // Estadísticas rápidas
  // -------------------------
  const total = reports.length;
  const criticas = reports.filter((r) => r.priority === "critica").length;
  const altas = reports.filter((r) => r.priority === "alta").length;
  const medias = reports.filter((r) => r.priority === "media").length;
  const bajas = reports.filter((r) => r.priority === "baja").length;

  // -------------------------
  // Vista principal
  // -------------------------
  const renderHome = () => (
    <div className="app-container">
      {/* BARRA SUPERIOR */}
      <header className="top-bar">
        <div className="brand">
          <span className="brand-small">Iniciativa ciudadana</span>
          <span className="brand-main">BALBOA ALERTA</span>
        </div>
        <div className="top-tagline">
          Plataforma ciudadana de reportes locales
        </div>
      </header>

      {/* HERO */}
      <section className="hero">
        <h1>¡BALBOA ALERTA ESTÁ VIVO!</h1>
        <p>
          Vecinos organizados reportando basura, daños, riesgos y problemas en
          tiempo real. Un distrito más limpio, más seguro, más nuestro.
        </p>

        <button className="hero-button" onClick={() => setView("form")}>
          Reportar incidencia
        </button>
      </section>

      {/* SEPARADOR ROJO */}
      <div className="divider" />

      {/* TABLERO DE ESTADO */}
      <section className="stats-section">
        <h2>Resumen rápido</h2>
        <div className="stats-grid">
          <div className="stat-card stat-total">
            <span className="stat-label">Total reportes</span>
            <span className="stat-number">{total}</span>
          </div>
          <div className="stat-card stat-critico">
            <span className="stat-label">Críticos</span>
            <span className="stat-number">{criticas}</span>
          </div>
          <div className="stat-card stat-alto">
            <span className="stat-label">Alta prioridad</span>
            <span className="stat-number">{altas}</span>
          </div>
          <div className="stat-card stat-medio">
            <span className="stat-label">Media</span>
            <span className="stat-number">{medias}</span>
          </div>
          <div className="stat-card stat-bajo">
            <span className="stat-label">Baja</span>
            <span className="stat-number">{bajas}</span>
          </div>
        </div>
      </section>

      {/* REPORTES RECIENTES */}
      <section className="reports-section">
        <div className="reports-header">
          <h2>Reportes recientes</h2>
          <span className="reports-count">
            {total} reporte{total !== 1 && "s"} registrado{total !== 1 && "s"}
          </span>
        </div>

        {loading ? (
          <p>Obteniendo información del servidor...</p>
        ) : reports.length === 0 ? (
          <div className="empty-box">
            Aún no hay reportes registrados. Sé el primero en reportar una
            incidencia en tu comunidad.
          </div>
        ) : (
          <div className="reports-list">
            {reports
              .slice()
              .reverse()
              .map((r) => (
                <article key={r.id} className="report-card">
                  <div className="report-header-row">
                    <h3>{r.type}</h3>
                    {r.zone && <span className="report-zone">{r.zone}</span>}
                  </div>

                  <div className="chips-row">
                    <span className={`chip chip-priority-${r.priority || "media"}`}>
                      Prioridad: {r.priority || "media"}
                    </span>
                    <span className="chip chip-status">
                      Estado: {r.status || "nuevo"}
                    </span>
                  </div>

                  <p className="report-description">{r.description}</p>

                  <p className="report-info">
                    <strong>Ubicación:</strong> {r.location}
                  </p>

                  {r.contact && (
                    <p className="report-info">
                      <strong>Contacto:</strong> {r.contact}
                    </p>
                  )}

                  <p className="report-footer">
                    {r.createdAt
                      ? new Date(r.createdAt).toLocaleString()
                      : ""}
                  </p>
                </article>
              ))}
          </div>
        )}
      </section>

      <footer className="footer">
        Balboa Alerta · Iniciativa ciudadana para La Chorrera
      </footer>
    </div>
  );

  // -------------------------
  // Vista formulario
  // -------------------------
  const renderReportForm = () => (
    <div className="app-container">
      <header className="top-bar">
        <div className="brand">
          <span className="brand-small">Iniciativa ciudadana</span>
          <span className="brand-main">BALBOA ALERTA</span>
        </div>
        <div className="top-tagline">Nuevo reporte</div>
      </header>

      <section className="form-section">
        <button className="back-button" onClick={() => setView("home")}>
          ← Volver al inicio
        </button>

        <h2>Nuevo reporte ciudadano</h2>
        <p className="form-description">
          Describe el problema con claridad. Esta información será la base para
          priorizar acciones en el territorio.
        </p>

        <form onSubmit={submitReport} className="report-form">
          <label>
            Tipo de incidencia *
            <select
              value={type}
              onChange={(e) => setType(e.target.value)}
              required
            >
              <option>Basura acumulada</option>
              <option>Alumbrado defectuoso</option>
              <option>Drenajes tapados</option>
              <option>Daño en vía pública</option>
              <option>Riesgo para peatones</option>
              <option>Agua estancada</option>
            </select>
          </label>

          <label>
            Descripción del problema *
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              required
              rows={4}
            />
          </label>

          <label>
            Ubicación aproximada *
            <input
              value={location}
              onChange={(e) => setLocation(e.target.value)}
              required
            />
          </label>

          <div className="form-row">
            <label>
              Prioridad
              <select
                value={priority}
                onChange={(e) => setPriority(e.target.value)}
              >
                <option value="critica">Crítica</option>
                <option value="alta">Alta</option>
                <option value="media">Media</option>
                <option value="baja">Baja</option>
              </select>
            </label>

            <label>
              Zona / sector
              <input
                value={zone}
                onChange={(e) => setZone(e.target.value)}
                placeholder="Ej: Barrio Balboa, Urb. X..."
              />
            </label>
          </div>

          <label>
            Contacto (opcional)
            <input
              value={contact}
              onChange={(e) => setContact(e.target.value)}
              placeholder="Nombre y/o teléfono"
            />
          </label>
          {/* Vista previa en mapa */}
          <div className="map-preview-box">
            <h3>Vista rápida en mapa</h3>
            <p className="map-preview-text">
              Usamos la ubicación / zona que escribas como referencia visual en
              Google Maps. La confirmación exacta siempre será en territorio.
            </p>
            <div className="map-frame-wrapper">
              <iframe
                src={mapPreviewUrl}
                loading="lazy"
                referrerPolicy="no-referrer-when-downgrade"
                title="Mapa de referencia"
              ></iframe>
            </div>
          </div>

          <div className="form-buttons">
            <button type="submit" className="primary-button">
              Enviar reporte
            </button>
            <button
              type="button"
              className="secondary-button"
              onClick={() => setView("home")}
            >
              Cancelar
            </button>
          </div>
        </form>
      </section>

      <footer className="footer">
        Balboa Alerta · Vecinos organizados, barrio más seguro
      </footer>
    </div>
  );

  // -------------------------
  // Render final
  // -------------------------
  return view === "home" ? renderHome() : renderReportForm();
}

export default App;
